          "negative_marks": 0,
          "explanation": "<p><a href=\"https://aptitude.gateoverflow.in/1774/cat-2000-question-19\" target=\"_blank\">https://aptitude.gateoverflow.in/1774/cat-2000-question-19</a></p>"
