          "negative_marks": 0,
          "explanation": "<p><a href=\"https://aptitude.gateoverflow.in/1739/cat-2001-question-80\" target=\"_blank\">https://aptitude.gateoverflow.in/1739/cat-2001-question-80</a></p>"
