          "negative_marks": 0,
          "explanation": "<p><a href=\"https://aptitude.gateoverflow.in/1851/cat-2004-question-117\" target=\"_blank\">https://aptitude.gateoverflow.in/1851/cat-2004-question-117</a></p>"
