          "negative_marks": 0,
          "explanation": "<p><a href=\"https://aptitude.gateoverflow.in/1681/cat-2008-question-90\" target=\"_blank\">https://aptitude.gateoverflow.in/1681/cat-2008-question-90</a></p>"
